  CLASS
	NAME "Escorrentía (mm)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-47 - -30"
    EXPRESSION ([pixel] >= -47 AND [pixel] < -30)
    COLOR 194 82 60
  END
  CLASS
	NAME "-30 - -20"
    EXPRESSION ([pixel] >= -30 AND [pixel] < -20)
    COLOR 219 122 37
  END
  CLASS
	NAME "-20 - -10"
    EXPRESSION ([pixel] >= -20 AND [pixel] < -10)
    COLOR 240 180 17
  END
  CLASS
	NAME "-10 - 10"
    EXPRESSION ([pixel] >= -10 AND [pixel] < 10)
    COLOR 252 240 3
  END
  CLASS
	NAME "10 - 50"
    EXPRESSION ([pixel] >= 10 AND [pixel] < 50)
    COLOR 123 237 0
  END
  CLASS
	NAME "50 - 100"
    EXPRESSION ([pixel] >= 50 AND [pixel] < 100)
    COLOR 6 212 27
  END
  CLASS
	NAME "100 - 150"
    EXPRESSION ([pixel] >= 100 AND [pixel] < 150)
    COLOR 27 168 124
  END
  CLASS
	NAME "150 - 200"
    EXPRESSION ([pixel] >= 150 AND [pixel] < 200)
    COLOR 24 117 140
  END
  CLASS
	NAME "200 - 231"
    EXPRESSION ([pixel] >= 200 AND [pixel] <= 231)
